import{_ as e,c as o,o as s,a1 as a}from"./chunks/framework.DDNAyvCW.js";const r="/assets/hosts.C4ZoDOIh.png",g=JSON.parse('{"title":"Host List Operations","description":"","frontmatter":{},"headers":[],"relativePath":"docs/hosts/index.md","filePath":"docs/hosts/index.md"}'),i={name:"docs/hosts/index.md"};function n(l,t,h,d,c,p){return s(),o("div",null,t[0]||(t[0]=[a('<h1 id="host-list-operations" tabindex="-1">Host List Operations <a class="header-anchor" href="#host-list-operations" aria-label="Permalink to &quot;Host List Operations&quot;">​</a></h1><p>The host list is your central dashboard for browsing, searching, and managing every server you have added to Chaterm, so you can connect to any host in seconds.</p><p><img src="'+r+'" alt=""></p><h2 id="open-the-host-list" tabindex="-1">Open the Host List <a class="header-anchor" href="#open-the-host-list" aria-label="Permalink to &quot;Open the Host List&quot;">​</a></h2><p>Open the left sidebar and click <strong>Hosts</strong>. The host list displays two views:</p><ul><li><strong>Direct Connection</strong> -- hosts you connect to over the network without an intermediary.</li><li><strong>Bastion Resources</strong> -- hosts that are reachable only through a bastion (jump server). Switch to this view by clicking the <strong>Bastion Resources</strong> tab.</li></ul><h2 id="search-and-filter" tabindex="-1">Search and Filter <a class="header-anchor" href="#search-and-filter" aria-label="Permalink to &quot;Search and Filter&quot;">​</a></h2><ol><li>Click the <strong>search box</strong> at the top of the host list.</li><li>Type an IP address, hostname, or alias.</li><li>Review the results that filter in real time as you type.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Combine search with the Bastion Resources view to narrow results to a specific access path.</p></div><h2 id="favorites" tabindex="-1">Favorites <a class="header-anchor" href="#favorites" aria-label="Permalink to &quot;Favorites&quot;">​</a></h2><ol><li>Right-click a host to open its context menu.</li><li>Select <strong>Add to Favorites</strong> to pin the host to your Favorites list.</li><li>To unpin, right-click the host again and select <strong>Remove from Favorites</strong>.</li></ol><p>Favorited hosts appear at the top of the list, giving you one-click access to the servers you use most.</p><h2 id="context-menu-operations" tabindex="-1">Context Menu Operations <a class="header-anchor" href="#context-menu-operations" aria-label="Permalink to &quot;Context Menu Operations&quot;">​</a></h2><p>Right-click any host to see the available actions:</p><table tabindex="0"><thead><tr><th>Action</th><th>Description</th></tr></thead><tbody><tr><td><strong>Connect</strong></td><td>Open an SSH session to the host.</td></tr><tr><td><strong>Edit</strong></td><td>Modify the host&#39;s connection settings.</td></tr><tr><td><strong>Clone</strong></td><td>Duplicate the host entry with a new name.</td></tr><tr><td><strong>Delete</strong></td><td>Remove the host from Chaterm permanently.</td></tr><tr><td><strong>Add to Favorites</strong></td><td>Pin the host to the top of the list.</td></tr><tr><td><strong>Remove from Favorites</strong></td><td>Unpin the host from Favorites.</td></tr></tbody></table><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><ul><li><strong>Group by purpose</strong> -- Organize hosts into groups such as <code>Production</code>, <code>Staging</code>, <code>Development</code>, or <code>Database Servers</code> to keep the list manageable.</li><li><strong>Use SSH keys</strong> -- Prefer key-based authentication over passwords. See <a href="/docs/manage/keys/">Key Management</a> for setup details.</li><li><strong>Add clear notes</strong> -- Record important details (environment, owner, special ports) so any team member can understand a host at a glance.</li><li><strong>Clean up regularly</strong> -- Review the list periodically and delete hosts that are decommissioned or no longer in use.</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./add-personal">Add a Personal Host</a> -- Add a host that connects directly over the network.</li><li><a href="./add-bastion">Add a Bastion Host</a> -- Add a host accessible through a bastion server.</li><li><a href="./add-router">Add a Router</a> -- Configure a router or jump host entry.</li><li><a href="./connect">Connect to a Host</a> -- Establish an SSH session and use the terminal.</li><li><a href="./edit-clone-delete">Edit, Clone, or Delete a Host</a> -- Modify or remove existing host entries.</li><li><a href="./import-export">Import and Export Hosts</a> -- Bulk-import or export your host list.</li></ul>',19)]))}const m=e(i,[["render",n]]);export{g as __pageData,m as default};
